import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { Region, ClanMember, Realm } from '../../types';
import { REALM_ORDER } from '../../constants';
import RegionMarker from './RegionMarker';
import RegionInfoPanel from './RegionInfoPanel';

interface Props {
    regions: Region[];
    members: ClanMember[];
    reputation: Record<string, number>;
    onSelectRegion: (region: Region | null) => void;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateRegion: (id: string, updates: Partial<Region>) => void;
    currentRegionId: string;
    onOverviewChange?: (isOverview: boolean) => void;
}

const WorldMap: React.FC<Props> = ({ 
    regions, 
    members, 
    reputation, 
    onSelectRegion, 
    currentRegionId, 
    onOverviewChange 
}) => {
    const VIEW_W = 1920;
    const VIEW_H = 1080;
    const MIN_PLAY_SCALE = 1.4; 
    const MAX_SCALE = 4.0;      
    const OVERVIEW_SCALE = 1.0; 

    const [camera, setCamera] = useState({ x: 0, y: 0, scale: 1.8 }); 
    const [isDragging, setIsDragging] = useState(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const isOverview = camera.scale <= OVERVIEW_SCALE;

    useEffect(() => {
        onOverviewChange?.(isOverview);
    }, [isOverview, onOverviewChange]);

    const getClampedPos = useCallback((x: number, y: number, scale: number) => {
        if (scale <= OVERVIEW_SCALE) return { x: 0, y: 0 };
        const scaledW = VIEW_W * scale;
        const scaledH = VIEW_H * scale;
        const limitX = Math.max(0, (scaledW - VIEW_W) / 2);
        const limitY = Math.max(0, (scaledH - VIEW_H) / 2);
        return {
            x: Math.max(-limitX, Math.min(limitX, x)),
            y: Math.max(-limitY, Math.min(limitY, y))
        };
    }, []);

    const handleZoom = (direction: 'in' | 'out') => {
        setCamera(prev => {
            let nextScale: number;
            if (direction === 'out') {
                if (prev.scale <= MIN_PLAY_SCALE) nextScale = OVERVIEW_SCALE;
                else nextScale = prev.scale * 0.85;
            } else {
                if (prev.scale <= OVERVIEW_SCALE) nextScale = MIN_PLAY_SCALE;
                else nextScale = Math.min(MAX_SCALE, prev.scale * 1.15);
            }
            nextScale = Math.max(OVERVIEW_SCALE, Math.min(MAX_SCALE, nextScale));
            const { x, y } = getClampedPos(prev.x, prev.y, nextScale);
            return { x, y, scale: nextScale };
        });
    };

    const handleWheel = (e: React.WheelEvent) => {
        handleZoom(e.deltaY > 0 ? 'out' : 'in');
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (e.button !== 0 || isOverview) return;
        setIsDragging(true);
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isDragging || isOverview) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;
        setCamera(prev => {
            const nextX = prev.x + dx;
            const nextY = prev.y + dy;
            const clamped = getClampedPos(nextX, nextY, prev.scale);
            return { ...clamped, scale: prev.scale };
        });
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => setIsDragging(false);

    // 灵脉路径定义
    const spiritVeins = useMemo(() => [
        "M 960 800 Q 1100 600 960 400 T 960 100", // 中央主脉
        "M 500 900 C 700 800 400 600 300 400",  // 支脉A
        "M 1400 850 Q 1200 700 1500 500 T 1600 200", // 支脉B
        "M 400 200 Q 600 400 200 600", // 西北支脉
        "M 1600 800 Q 1400 600 1800 400" // 东南支脉
    ], []);

    const maxClanRealmIdx = useMemo(() => {
        return members
            .filter(m => m.family === '望月李氏')
            .reduce((max, m) => {
                const idx = REALM_ORDER.indexOf(m.realm);
                return idx > max ? idx : max;
            }, 0);
    }, [members]);

    const selectedRegion = useMemo(() => {
        return regions.find(r => r.id === currentRegionId) || null;
    }, [regions, currentRegionId]);

    return (
        <div 
            className={`w-full h-full relative overflow-hidden bg-[#0a0f0d] ${isOverview ? 'cursor-default' : (isDragging ? 'cursor-grabbing' : 'cursor-grab')}`}
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
        >
            {/* 全景模式下的云雾遮罩 */}
            <div 
                className="absolute inset-0 z-[60] pointer-events-none transition-opacity duration-1000"
                style={{ opacity: isOverview ? 0.4 : 0, background: 'radial-gradient(circle, transparent 20%, #000 100%)' }}
            ></div>

            <div 
                className="absolute inset-0 w-[1920px] h-[1080px] left-1/2 top-1/2 world-map-main origin-center"
                style={{ 
                    transform: `translate(-50%, -50%) translate(${camera.x}px, ${camera.y}px) scale(${camera.scale})`,
                    transition: isDragging ? 'none' : 'transform 0.4s cubic-bezier(0.2, 0, 0.2, 1)', 
                    willChange: 'transform'
                }}
            >
                {/* 1. 灵脉层 (Spiritual Veins) */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-40" viewBox="0 0 1920 1080">
                    <defs>
                        <filter id="glow">
                            <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
                            <feMerge>
                                <feMergeNode in="coloredBlur"/>
                                <feMergeNode in="SourceGraphic"/>
                            </feMerge>
                        </filter>
                    </defs>
                    {spiritVeins.map((d, i) => (
                        <path 
                            key={i} d={d} 
                            fill="none" 
                            stroke={i === 0 ? "#C9A063" : "#4D7C6B"} 
                            strokeWidth="4" 
                            className="spirit-vein-path" 
                            filter="url(#glow)"
                        />
                    ))}
                </svg>

                {/* 2. 势力晕染层 (Ink Diffusion) */}
                <div className="absolute inset-0 ink-territory-container z-5">
                    {regions.filter(r => r.isDiscovered && r.owner !== '无').map(r => (
                        <div 
                            key={`territory-${r.id}`}
                            className="absolute transform -translate-x-1/2 -translate-y-1/2 ink-blob"
                            style={{
                                left: `${r.x}%`,
                                top: `${r.y}%`,
                                width: r.owner === '望月李氏' ? '300px' : '200px',
                                height: r.owner === '望月李氏' ? '300px' : '200px',
                                backgroundColor: r.owner === '望月李氏' ? 'rgba(201, 160, 99, 0.8)' : 'rgba(77, 124, 107, 0.8)',
                                opacity: isOverview ? 0.9 : 0.6
                            }}
                        />
                    ))}
                </div>

                {/* 3. 动态云雾层 (Moving Mist) */}
                <div className="mist-layer z-10"></div>

                {/* 4. 地区标记层 */}
                {regions.map(region => {
                    if (!region.isDiscovered) return null;
                    const isHome = region.id === 'li_clan_home';
                    const isOccupied = !!region.activeMission || !!region.guardMemberId;
                    const isSelected = currentRegionId === region.id;

                    return (
                        <RegionMarker 
                            key={region.id}
                            region={region}
                            isHome={isHome}
                            isSelected={isSelected}
                            isOccupied={isOccupied}
                            showLabel={camera.scale > 1.2 || isSelected}
                            onSelect={onSelectRegion}
                        />
                    );
                })}
            </div>

            {/* 地区详情面板 */}
            {selectedRegion && (
                <RegionInfoPanel 
                    region={selectedRegion}
                    maxClanRealmIdx={maxClanRealmIdx}
                    onClose={() => onSelectRegion(null)}
                />
            )}

            {/* 视角控制 HUD */}
            <div className="absolute bottom-8 right-8 z-50 flex flex-col gap-2 transition-opacity duration-500" style={{ opacity: isOverview ? 0 : 1 }}>
                <button onClick={() => handleZoom('in')} className="w-10 h-10 bg-bg-panel/80 border border-border-soft text-accent-gold rounded flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold">＋</button>
                <button onClick={() => handleZoom('out')} className="w-10 h-10 bg-bg-panel/80 border border-border-soft text-accent-gold rounded flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold">－</button>
            </div>
        </div>
    );
};

export default WorldMap;

import React from 'react';
import { Region, ClanMember, RegionCategory, Realm } from '../../types';
import { getRegionImage, getFactionTierImage } from '../../assets/imageRegistry';

interface RegionMarkerProps {
    region: Region;
    isHome: boolean;
    isSelected: boolean;
    isOccupied: boolean;
    showLabel: boolean;
    onSelect: (region: Region) => void;
}

const RegionMarker: React.FC<RegionMarkerProps> = ({ 
    region, 
    isHome, 
    isSelected, 
    isOccupied, 
    showLabel, 
    onSelect 
}) => {
    const getCategorySizeClasses = (category: RegionCategory, id: string) => {
        const isHome = id === 'li_clan_home';
        switch (category) {
            case 'Stakeholder': return isHome ? 'w-24 h-24' : 'w-16 h-16';
            case 'Natural': return 'w-14 h-14';
            case 'Mystic': return 'w-18 h-18';
            case 'Resource': return 'w-12 h-12';
            default: return 'w-14 h-14';
        }
    };

    const renderIcon = () => {
        let imageUrl: string;
        if (region.category === 'Stakeholder') {
            const isSect = region.type === 'sect' || region.owner.includes('宗') || region.owner.includes('门');
            imageUrl = getFactionTierImage(isSect, region.difficulty);
        } else {
            imageUrl = getRegionImage(region.type, region.category === 'Mystic');
        }
        return (
            <div className="w-full h-full flex items-center justify-center overflow-hidden rounded-full p-2">
                <img 
                    src={imageUrl} 
                    alt={region.type} 
                    className="w-full h-full object-contain filter brightness-90 contrast-125"
                    onError={(e) => {
                        (e.target as HTMLImageElement).src = 'https://api.iconify.design/mdi:mountain.svg?color=%234D7C6B';
                    }}
                />
            </div>
        );
    };

    const sizeClass = getCategorySizeClasses(region.category, region.id);

    return (
        <div 
            className={`absolute transform -translate-x-1/2 -translate-y-1/2 group transition-all duration-700 ${isSelected ? 'z-40 scale-125' : 'z-20 hover:scale-110'}`}
            style={{ left: `${region.x}%`, top: `${region.y}%` }}
        >
            <button 
                onClick={(e) => { e.stopPropagation(); onSelect(region); }} 
                className="flex flex-col items-center group/btn relative"
            >
                {/* 标记下方的动态水墨光晕 */}
                <div className={`absolute -inset-4 rounded-full blur-xl opacity-0 group-hover/btn:opacity-60 transition-opacity duration-500 pointer-events-none
                    ${isHome ? 'bg-amber-600/30' : (region.category === 'Mystic' ? 'bg-purple-600/30' : 'bg-emerald-600/20')}`} 
                />

                <div className={`${sizeClass} flex items-center justify-center rounded-full border-[3px] relative transition-all duration-500
                    ${isHome ? 'bg-[#1e1310] border-accent-gold shadow-[0_0_30px_rgba(201,160,99,0.5)]' : 
                      (region.category === 'Mystic' ? 'bg-[#1a1215] border-purple-400 shadow-[0_0_20px_rgba(168,85,247,0.4)] animate-pulse' :
                      (isSelected ? 'bg-bg-panel border-accent-gold' : 
                      (region.owner === '望月李氏' ? 'bg-[#1e1310] border-accent-jade/60' :
                      'bg-black/40 border-border-soft')))} 
                    backdrop-blur-sm`}
                >
                    {renderIcon()}

                    {/* 派遣状态角标 */}
                    {isOccupied && (
                        <div className="absolute -top-3 -right-3 w-7 h-7 bg-amber-600 rounded-full border-2 border-[#f4e4bc] flex items-center justify-center animate-bounce shadow-xl z-30">
                            <span className="text-[10px]">⏳</span>
                        </div>
                    )}
                </div>

                {/* 水墨风格标签 */}
                {showLabel && (
                    <div className="mt-3 filter drop-shadow-[0_4px_4px_rgba(0,0,0,0.8)] animate-fade-in pointer-events-none">
                        <span className="text-[13px] font-bold bg-[#f4e4bc] px-3 py-1 rounded-sm border border-[#2c1810] text-[#1a1310] font-serif whitespace-nowrap tracking-widest shadow-lg">
                            {region.name}
                        </span>
                    </div>
                )}
            </button>
        </div>
    );
};

export default RegionMarker;

