                                borderRadius: '50%',
                                opacity: isOverview ? 1 : 0.4
                            }}
                        />
                    ))}
                </div>

                {/* 3. 云海层 (Moving Cloud Mist) */}
                <div className="mist-layer z-10" style={{ opacity: Math.max(0.05, 0.2 - (camera.scale - 1) * 0.1) }} />

                {/* 4. 地区标记层 (Markers) */}
                {regions.map(region => {
                    if (!region.isDiscovered) return null;
                    const isSelected = currentRegionId === region.id;
                    return (
                        <RegionMarker 
                            key={region.id}
                            region={region}
                            isHome={region.id === 'li_clan_home'}
                            isSelected={isSelected}
                            isOccupied={!!region.activeMission || !!region.guardMemberId}
                            showLabel={camera.scale > 1.3 || isSelected}
