                    maxClanRealmIdx={maxClanRealmIdx}
                    onClose={() => onSelectRegion(null)}
                />
            )}

            {/* 控制器 */}
            <div className="absolute bottom-10 right-10 z-50 flex flex-col gap-3 transition-opacity duration-500" style={{ opacity: isOverview ? 0.3 : 1 }}>
                <button onClick={() => handleZoom('in')} className="w-12 h-12 bg-bg-panel/90 border border-accent-gold/40 text-accent-gold rounded-full flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold shadow-xl">＋</button>
                <button onClick={() => handleZoom('out')} className="w-12 h-12 bg-bg-panel/90 border border-accent-gold/40 text-accent-gold rounded-full flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold shadow-xl">－</button>
