import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { Region, ClanMember } from '../../types';
import { REALM_ORDER } from '../../constants';
import RegionMarker from './RegionMarker';
import RegionInfoPanel from './RegionInfoPanel';

interface Props {
    regions: Region[];
    members: ClanMember[];
    reputation: Record<string, number>;
    onSelectRegion: (region: Region | null) => void;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateRegion: (id: string, updates: Partial<Region>) => void;
    currentRegionId: string;
    onOverviewChange?: (isOverview: boolean) => void;
}

const WorldMap: React.FC<Props> = ({ 
    regions, 
    members, 
    onSelectRegion, 
    currentRegionId, 
    onOverviewChange 
}) => {
    const VIEW_W = 1920;
    const VIEW_H = 1080;
    const OVERVIEW_SCALE = 1.0; 
    const MIN_PLAY_SCALE = 1.2;
    const MAX_SCALE = 4.0;

    const [camera, setCamera] = useState({ x: 0, y: 0, scale: 1.6 }); 
    const [isDragging, setIsDragging] = useState(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const isOverview = camera.scale <= OVERVIEW_SCALE;

    useEffect(() => {
        onOverviewChange?.(isOverview);
    }, [isOverview, onOverviewChange]);

    const getClampedPos = useCallback((x: number, y: number, scale: number) => {
        if (scale <= OVERVIEW_SCALE) return { x: 0, y: 0 };
        const scaledW = VIEW_W * scale;
        const scaledH = VIEW_H * scale;
        const limitX = Math.max(0, (scaledW - VIEW_W) / 2);
        const limitY = Math.max(0, (scaledH - VIEW_H) / 2);
        return {
            x: Math.max(-limitX, Math.min(limitX, x)),
            y: Math.max(-limitY, Math.min(limitY, y))
        };
    }, []);

    const handleZoom = (direction: 'in' | 'out') => {
        setCamera(prev => {
            let nextScale: number;
            if (direction === 'out') {
                if (prev.scale <= MIN_PLAY_SCALE) nextScale = OVERVIEW_SCALE;
                else nextScale = prev.scale * 0.8;
            } else {
                if (prev.scale <= OVERVIEW_SCALE) nextScale = MIN_PLAY_SCALE;
                else nextScale = Math.min(MAX_SCALE, prev.scale * 1.25);
            }
            nextScale = Math.max(OVERVIEW_SCALE, Math.min(MAX_SCALE, nextScale));
            const { x, y } = getClampedPos(prev.x, prev.y, nextScale);
            return { x, y, scale: nextScale };
        });
    };

    const handleWheel = (e: React.WheelEvent) => {
        handleZoom(e.deltaY > 0 ? 'out' : 'in');
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (e.button !== 0 || isOverview) return;
        setIsDragging(true);
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isDragging || isOverview) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;
        setCamera(prev => {
            const nextX = prev.x + dx;
            const nextY = prev.y + dy;
            const clamped = getClampedPos(nextX, nextY, prev.scale);
            return { ...clamped, scale: prev.scale };
        });
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => setIsDragging(false);

    // 势力分组逻辑
    const factionGroups = useMemo(() => {
        const groups: Record<string, Region[]> = {};
        regions.filter(r => r.isDiscovered && r.owner !== '无').forEach(r => {
            if (!groups[r.owner]) groups[r.owner] = [];
            groups[r.owner].push(r);
        });
        return groups;
    }, [regions]);

    // 绘制灵脉
    const spiritVeins = useMemo(() => [
        "M 960 1080 Q 900 800 960 540 T 960 0", 
        "M 200 1080 C 400 800 200 400 600 200", 
        "M 1720 1080 C 1520 800 1720 400 1320 200", 
        "M 0 540 Q 400 400 960 540 T 1920 540", 
    ], []);

    // 望月湖水墨形状
    const lakePath = "M 800,450 C 700,400 600,500 650,600 C 700,700 850,750 1000,700 C 1150,650 1200,500 1100,400 C 1000,350 900,500 800,450 Z";

    const selectedRegion = useMemo(() => regions.find(r => r.id === currentRegionId) || null, [regions, currentRegionId]);

    const maxClanRealmIdx = useMemo(() => {
        return members
            .filter(m => m.family === '望月李氏')
            .reduce((max, m) => Math.max(max, REALM_ORDER.indexOf(m.realm)), 0);
    }, [members]);

    // 势力配色表
    const factionColors: Record<string, string> = {
        '望月李氏': '#C9A063',
        '北寒宗': '#A5F3FC', // 极地蓝
        '天一剑宗': '#94A3B8', // 剑锋灰
        '离火门': '#EF4444', // 离火红
        '魏家': '#8B5CF6', // 阵法紫
        '邵家': '#78350F', // 铁矿褐
        '齐家': '#10B981', // 商道绿
        '万花谷': '#F472B6', // 花谷粉
    };

    return (
        <div 
            className={`w-full h-full relative overflow-hidden bg-black ${isOverview ? 'cursor-default' : (isDragging ? 'cursor-grabbing' : 'cursor-grab')}`}
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
        >
            <div className="absolute inset-0 w-[1920px] h-[1080px] left-1/2 top-1/2 world-map-main origin-center"
                style={{ 
                    transform: `translate(-50%, -50%) translate(${camera.x}px, ${camera.y}px) scale(${camera.scale})`,
                    transition: isDragging ? 'none' : 'transform 0.5s cubic-bezier(0.2, 0, 0.2, 1)', 
                    willChange: 'transform'
                }}>

                {/* 1. 地理底层：望月湖 & 灵脉 */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none z-0" viewBox="0 0 1920 1080">
                    {/* 绘制望月湖 */}
                    <path d={lakePath} fill="#94A3B8" fillOpacity="0.15" stroke="#4D7C6B" strokeWidth="3" strokeDasharray="5,5" className="animate-pulse" />
                    <text x="960" y="540" textAnchor="middle" className="font-cursive text-3xl fill-accent-jade/40 select-none">望月湖</text>

                    {/* 绘制灵脉 */}
                    {spiritVeins.map((d, i) => (
                        <path key={i} d={d} fill="none" stroke={i === 0 ? "#C9A063" : "#4D7C6B"} strokeWidth="2" className="spirit-vein-path" />
                    ))}
                </svg>

                {/* 2. 势力勾边层 (仅全貌模式显示) */}
                <div 
                    className="absolute inset-0 territory-outline-container z-5"
                    style={{ 
                        opacity: isOverview ? 1 : 0,
                        visibility: camera.scale > 1.1 ? 'hidden' : 'visible' 
                    }}
                >
                    {Object.entries(factionGroups).map(([faction, factionRegions]) => {
                        const color = factionColors[faction] || '#5F6B66';
                        return (
                            <div key={`faction-line-${faction}`} className="absolute inset-0">
                                {factionRegions.map(r => (
                                    <div 
                                        key={`blob-node-${r.id}`}
                                        className="absolute transform -translate-x-1/2 -translate-y-1/2"
                                        style={{
                                            left: `${r.x}%`,
                                            top: `${r.y}%`,
                                            width: faction === '望月李氏' ? '320px' : '240px', 
                                            height: faction === '望月李氏' ? '320px' : '240px',
                                            background: color,
                                            borderRadius: '50%',
                                        }}
                                    />
                                ))}
                            </div>
                        );
                    })}
                </div>

                {/* 3. 云海层 */}
                <div className="mist-layer z-10" />

                {/* 4. 地区标记 */}
                {regions.map(region => {
                    if (!region.isDiscovered) return null;
                    const isSelected = currentRegionId === region.id;
                    return (
                        <RegionMarker 
                            key={region.id}
                            region={region}
                            isHome={region.id === 'li_clan_home'}
                            isSelected={isSelected}
                            isOccupied={!!region.activeMission || !!region.guardMemberId}
                            showLabel={camera.scale > 1.3 || isSelected}
                            onSelect={onSelectRegion}
                        />
                    );
                })}
            </div>

            {selectedRegion && (
                <RegionInfoPanel region={selectedRegion} maxClanRealmIdx={maxClanRealmIdx} onClose={() => onSelectRegion(null)} />
            )}

            {/* UI 提示：操作指南 */}
            <div className={`absolute bottom-10 left-1/2 -translate-x-1/2 px-6 py-3 bg-bg-panel/80 backdrop-blur-md border border-accent-gold/20 rounded-full text-accent-gold/60 text-xs tracking-widest transition-opacity duration-1000 ${isOverview ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                滚轮缩放进入据点 ◈ 鼠标拖拽移动寰宇
            </div>

            <div className="absolute bottom-10 right-10 z-50 flex flex-col gap-3 transition-opacity duration-500" style={{ opacity: isOverview ? 0.3 : 1 }}>
                <button onClick={() => handleZoom('in')} className="w-12 h-12 bg-bg-panel/90 border border-accent-gold/40 text-accent-gold rounded-full flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold">＋</button>
                <button onClick={() => handleZoom('out')} className="w-12 h-12 bg-bg-panel/90 border border-accent-gold/40 text-accent-gold rounded-full flex items-center justify-center hover:bg-accent-gold hover:text-bg-main transition-all font-bold">－</button>
            </div>
        </div>
    );
};

